const originalText = String($json.command_text || $json.text || '').trim();
const extractTicketId = (value) => {
  const rawValue = String(value || '').trim();
  if (!rawValue) return null;
  const direct = Number(rawValue);
  if (Number.isInteger(direct) && direct > 0) return direct;
  const match = rawValue.match(/(?:^|\b)(?:ticket\s+)?(?:t\s*[-:#]?\s*)?(\d+)(?:\b|$)/i);
  if (!match) return null;
  const parsed = Number(match[1]);
  return Number.isInteger(parsed) && parsed > 0 ? parsed : null;
};
const normalizeWord = (value) => String(value || '').trim().toLowerCase();

let addorderAction = 'patch';
let addorderPatchText = '';
let ticketId = null;
let replyText = '';

if (!/^\/+addorder\b/i.test(originalText)) {
  replyText = 'Không nhận ra lệnh /addorder.';
} else {
  const body = originalText.replace(/^\/+addorder\b/i, '').trim();
  const tokens = body ? body.split(/\s+/).filter(Boolean) : [];
  if (['show', 'confirm', 'cancel', 'reset'].includes(normalizeWord(tokens[0]))) {
    addorderAction = normalizeWord(tokens.shift());
  }
  if (normalizeWord(tokens[0]) === 'ticket') {
    tokens.shift();
  }
  if (tokens.length) {
    ticketId = extractTicketId(tokens[0]);
    if (ticketId) tokens.shift();
  }
  if (!ticketId) {
    ticketId = extractTicketId(body);
  }
  addorderPatchText = tokens.join(' ').trim();

  if (!ticketId) {
    replyText = 'Thiếu ticket. Ví dụ: /addorder t-3 tên ...';
  } else if (addorderAction === 'patch' && !addorderPatchText) {
    replyText = 'Thiếu nội dung. Dùng /addorder show t-3 hoặc /addorder t-3 tên ...';
  }
}

return [{
  json: {
    ...$json,
    command_text: originalText,
    addorder_action: addorderAction,
    addorder_patch_text: addorderPatchText,
    ticket_id: ticketId || null,
    ticket_ref_raw: ticketId ? ('T-' + ticketId) : '',
    addorder_has_error: Boolean(replyText),
    reply_text: replyText,
  },
}];

const base = $('Code Parse AddOrder Command').first().json;
const row = $input.first()?.json || {};

const parseJson = (value) => {
  if (value && typeof value === 'object') return value;
  if (typeof value !== 'string') return {};
  try {
    return JSON.parse(value);
  } catch {
    return {};
  }
};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const digitsOnly = (value) => String(value || '').replace(/[^\d]/g, '');
const numberOrNull = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};
const coalesceText = (...values) => {
  for (const value of values) {
    const text = safeText(value);
    if (text) return text;
  }
  return '';
};
const coalesceNumber = (...values) => {
  for (const value of values) {
    const parsed = numberOrNull(value);
    if (parsed !== null) return parsed;
  }
  return null;
};

const ticket = parseJson(row.ticket_row);
const customer = parseJson(row.customer_row);
const draft = parseJson(row.draft_row);
const mergedSnapshot = parseJson(draft.merged_snapshot);
const productSearchResult = Array.isArray(parseJson(draft.product_search_result)) ? parseJson(draft.product_search_result) : [];
const locationSearchResult = parseJson(draft.location_search_result);

const baseSnapshot = {
  customer_name: coalesceText(customer.fullname, ticket.fullname),
  phone: digitsOnly(coalesceText(customer.phone, ticket.phone)),
  address: coalesceText(customer.address),
  city_name: coalesceText(customer.customer_city),
  city_id: null,
  district_name: coalesceText(customer.customer_district),
  district_id: null,
  ward_name: '',
  ward_id: null,
  location_version: 'v1',
  product_query: coalesceText(customer.products_interested, ticket.products_interested),
  product_id: null,
  product_code: '',
  product_name: '',
  unit_price: null,
  quantity: 1,
  note: '',
  customer_ship_fee: null,
  deposit_amount: null,
  transfer_amount: null,
};

const currentSnapshot = {
  ...baseSnapshot,
  ...(mergedSnapshot && typeof mergedSnapshot === 'object' ? mergedSnapshot : {}),
  customer_name: coalesceText(draft.customer_name, mergedSnapshot.customer_name, baseSnapshot.customer_name),
  phone: digitsOnly(coalesceText(draft.phone, mergedSnapshot.phone, baseSnapshot.phone)),
  address: coalesceText(draft.address, mergedSnapshot.address, baseSnapshot.address),
  city_name: coalesceText(draft.city_name, mergedSnapshot.city_name, baseSnapshot.city_name),
  city_id: coalesceNumber(draft.city_id, mergedSnapshot.city_id, baseSnapshot.city_id),
  district_name: coalesceText(draft.district_name, mergedSnapshot.district_name, baseSnapshot.district_name),
  district_id: coalesceNumber(draft.district_id, mergedSnapshot.district_id, baseSnapshot.district_id),
  ward_name: coalesceText(draft.ward_name, mergedSnapshot.ward_name, baseSnapshot.ward_name),
  ward_id: coalesceNumber(draft.ward_id, mergedSnapshot.ward_id, baseSnapshot.ward_id),
  location_version: coalesceText(draft.location_version, mergedSnapshot.location_version, baseSnapshot.location_version) || 'v1',
  product_query: coalesceText(draft.product_query, mergedSnapshot.product_query, baseSnapshot.product_query),
  product_id: coalesceNumber(draft.product_id, mergedSnapshot.product_id),
  product_code: coalesceText(draft.product_code, mergedSnapshot.product_code),
  product_name: coalesceText(draft.product_name, mergedSnapshot.product_name),
  unit_price: coalesceNumber(draft.unit_price, mergedSnapshot.unit_price),
  quantity: Math.max(1, Math.round(coalesceNumber(draft.quantity, mergedSnapshot.quantity, 1) || 1)),
  note: coalesceText(draft.note, mergedSnapshot.note),
  customer_ship_fee: coalesceNumber(draft.customer_ship_fee, mergedSnapshot.customer_ship_fee),
  deposit_amount: coalesceNumber(draft.deposit_amount, mergedSnapshot.deposit_amount),
  transfer_amount: coalesceNumber(draft.transfer_amount, mergedSnapshot.transfer_amount),
};

let replyText = safeText(base.reply_text);
if (!ticket.id && !replyText) {
  replyText = base.ticket_id ? ('Không thấy ticket T-' + base.ticket_id + '.') : 'Thiếu ticket. Ví dụ: /addorder t-3 tên ...';
}
if (!replyText && draft.status === 'created' && base.addorder_action !== 'show') {
  replyText = draft.nhanh_order_id
    ? ('T-' + base.ticket_id + ' đã tạo đơn Nhanh ' + draft.nhanh_order_id + '. Chưa hỗ trợ sửa bằng /addorder.')
    : ('T-' + base.ticket_id + ' đã chốt đơn. Chưa hỗ trợ sửa bằng /addorder.');
}

const needsAiPatch = !replyText && ['patch', 'confirm'].includes(base.addorder_action) && Boolean(safeText(base.addorder_patch_text));
const promptSnapshot = JSON.stringify(currentSnapshot, null, 2);
const addorderAiPrompt = [
  'Command gốc: ' + safeText(base.command_text),
  'Action: ' + safeText(base.addorder_action),
  'Ticket: ' + (base.ticket_ref_raw || ''),
  'Current snapshot:',
  promptSnapshot,
  'Patch text: ' + safeText(base.addorder_patch_text),
].join('\n');

return [{
  json: {
    ...base,
    ticket_row: ticket,
    customer_row: customer,
    draft_row: draft,
    base_snapshot: baseSnapshot,
    current_snapshot: currentSnapshot,
    product_search_result: productSearchResult,
    location_search_result: locationSearchResult,
    customer_phase_state_id: draft.customer_phase_state_id || ticket.customer_phase_state_id || customer.id || null,
    order_draft_id: draft.id || null,
    order_draft_status: safeText(draft.status),
    app_order_id: safeText(draft.app_order_id),
    nhanh_order_id: draft.nhanh_order_id || null,
    created_order_tracking_url: safeText(draft.nhanh_tracking_url),
    needs_ai_patch: needsAiPatch,
    addorder_ai_prompt: addorderAiPrompt,
    reply_text: replyText,
  },
}];

const base = $('Code Build AddOrder Context').first().json;
const raw = $json.output ?? $json.text ?? $json;
let text = '';
if (typeof raw === 'string') {
  text = raw.trim();
} else {
  text = JSON.stringify(raw);
}
text = text.replace(/^\`\`\`json\s*/i, '').replace(/^\`\`\`\s*/i, '').replace(/\s*\`\`\`$/i, '').trim();
let parsed = {};
try {
  parsed = JSON.parse(text);
} catch {
  parsed = {};
}
if (parsed && typeof parsed.output === 'object' && parsed.output !== null) {
  parsed = parsed.output;
}
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const digitsOnly = (value) => String(value || '').replace(/[^\d]/g, '');
const parseMoney = (value) => {
  const rawValue = safeText(value);
  if (!rawValue) return null;
  const normalized = rawValue.toLowerCase().replace(/[,\.](?=\d{3}\b)/g, '').replace(/\./g, '').replace(/,/g, '.');
  const match = normalized.match(/(\d+(?:\.\d+)?)(k)?/i);
  if (!match) return null;
  let amount = Number(match[1]);
  if (!Number.isFinite(amount)) return null;
  if (match[2]) amount *= 1000;
  return Math.round(amount);
};
const parseNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};
const patchText = safeText(base.addorder_patch_text);

let quantity = parseNumber(parsed.quantity);
if ((!quantity || quantity < 1) && patchText) {
  const quantityMatch = patchText.match(/(?:^|\s)x\s*(\d+)(?:\s|$)/i) || patchText.match(/(?:so luong|sl|qty)\s*(\d+)/i);
  if (quantityMatch) quantity = Number(quantityMatch[1]);
}
if (quantity !== null) quantity = Math.max(1, Math.round(quantity));

let phone = digitsOnly(parsed.phone);
if (!phone && patchText) {
  const phoneMatch = patchText.match(/(?:^|\D)(0\d{9,10})(?:\D|$)/);
  if (phoneMatch) phone = digitsOnly(phoneMatch[1]);
}

const parseMoneyFromPatch = (regex) => {
  const match = patchText.match(regex);
  return match ? parseMoney(match[1]) : null;
};

const customerShipFee = parseNumber(parsed.customer_ship_fee) ?? parseMoneyFromPatch(/(?:ship|phi ship|thu ship)\s*([\d.,kK]+)/i);
const depositAmount = parseNumber(parsed.deposit_amount) ?? parseMoneyFromPatch(/(?:coc|dat coc)\s*([\d.,kK]+)/i);
const transferAmount = parseNumber(parsed.transfer_amount) ?? parseMoneyFromPatch(/(?:chuyen khoan|ck)\s*([\d.,kK]+)/i);

const unsupportedFields = Array.isArray(parsed.unsupported_fields)
  ? parsed.unsupported_fields.map((value) => safeText(value)).filter(Boolean)
  : [];

return [{
  json: {
    ...base,
    ai_raw_patch_output: text,
    parsed_patch: {
      customer_name: safeText(parsed.customer_name),
      phone,
      address: safeText(parsed.address),
      city_name: safeText(parsed.city_name),
      district_name: safeText(parsed.district_name),
      ward_name: safeText(parsed.ward_name),
      product_query: safeText(parsed.product_query),
      quantity,
      unit_price: parseNumber(parsed.unit_price),
      note: safeText(parsed.note),
      customer_ship_fee: customerShipFee,
      deposit_amount: depositAmount,
      transfer_amount: transferAmount,
      clarification_text: safeText(parsed.clarification_text),
      unsupported_fields: unsupportedFields,
      confidence: parseNumber(parsed.confidence) ?? 0,
    },
  },
}];

const data = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const digitsOnly = (value) => String(value || '').replace(/[^\d]/g, '');
const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const numberOrNull = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};
const cloneJson = (value) => JSON.parse(JSON.stringify(value || {}));
const snapshot = data.addorder_action === 'reset'
  ? cloneJson(data.base_snapshot)
  : cloneJson(data.current_snapshot);
const patch = data.parsed_patch && typeof data.parsed_patch === 'object' ? data.parsed_patch : {};
const patchBusinessKeys = ['customer_name', 'phone', 'address', 'city_name', 'district_name', 'ward_name', 'product_query', 'quantity', 'unit_price', 'note', 'customer_ship_fee', 'deposit_amount', 'transfer_amount'];
const hasPatchValue = patchBusinessKeys.some((key) => {
  const value = patch[key];
  if (Array.isArray(value)) return value.length > 0;
  return value !== null && value !== undefined && String(value).trim() !== '';
});
const setText = (key, value) => {
  const text = safeText(value);
  if (text) snapshot[key] = text;
};
const setNumber = (key, value) => {
  const parsed = numberOrNull(value);
  if (parsed !== null) snapshot[key] = parsed;
};

if (data.addorder_action !== 'reset') {
  setText('customer_name', patch.customer_name);
  if (safeText(patch.phone)) snapshot.phone = digitsOnly(patch.phone);
  setText('address', patch.address);
  setText('city_name', patch.city_name);
  setText('district_name', patch.district_name);
  setText('ward_name', patch.ward_name);
  setText('product_query', patch.product_query);
  setNumber('quantity', patch.quantity);
  setNumber('unit_price', patch.unit_price);
  setText('note', patch.note);
  setNumber('customer_ship_fee', patch.customer_ship_fee);
  setNumber('deposit_amount', patch.deposit_amount);
  setNumber('transfer_amount', patch.transfer_amount);
}

snapshot.phone = digitsOnly(snapshot.phone);
snapshot.quantity = Math.max(1, Math.round(numberOrNull(snapshot.quantity) || 1));
snapshot.location_version = safeText(snapshot.location_version) || 'v1';

const productQueryChanged = normalizeText(snapshot.product_query) !== normalizeText(data.current_snapshot?.product_query || '');
const cityChanged = normalizeText(snapshot.city_name) !== normalizeText(data.current_snapshot?.city_name || '');
const districtChanged = normalizeText(snapshot.district_name) !== normalizeText(data.current_snapshot?.district_name || '');

if (productQueryChanged) {
  snapshot.product_id = null;
  snapshot.product_code = '';
  snapshot.product_name = '';
  if (numberOrNull(patch.unit_price) === null) snapshot.unit_price = null;
}
if (cityChanged) {
  snapshot.city_id = null;
  snapshot.district_id = null;
  snapshot.ward_id = null;
  snapshot.ward_name = '';
}
if (districtChanged) {
  snapshot.district_id = null;
  snapshot.ward_id = null;
  snapshot.ward_name = '';
}

let replyText = safeText(data.reply_text);
if (!replyText && data.addorder_action === 'patch' && !safeText(data.addorder_patch_text)) {
  replyText = 'Thiếu nội dung cập nhật.';
}
if (!replyText && data.addorder_action === 'patch' && !hasPatchValue && safeText(patch.clarification_text)) {
  replyText = safeText(patch.clarification_text);
}

return [{
  json: {
    ...data,
    draft_snapshot: snapshot,
    customer_name: safeText(snapshot.customer_name),
    phone: digitsOnly(snapshot.phone),
    address: safeText(snapshot.address),
    city_name: safeText(snapshot.city_name),
    city_id: numberOrNull(snapshot.city_id),
    district_name: safeText(snapshot.district_name),
    district_id: numberOrNull(snapshot.district_id),
    ward_name: safeText(snapshot.ward_name),
    ward_id: numberOrNull(snapshot.ward_id),
    product_query: safeText(snapshot.product_query),
    product_id: numberOrNull(snapshot.product_id),
    product_code: safeText(snapshot.product_code),
    product_name: safeText(snapshot.product_name),
    unit_price: numberOrNull(snapshot.unit_price),
    quantity: snapshot.quantity,
    note: safeText(snapshot.note),
    customer_ship_fee: numberOrNull(snapshot.customer_ship_fee),
    deposit_amount: numberOrNull(snapshot.deposit_amount),
    transfer_amount: numberOrNull(snapshot.transfer_amount),
    needs_product_lookup: Boolean(safeText(snapshot.product_query) && !numberOrNull(snapshot.product_id)),
    needs_city_lookup: Boolean(safeText(snapshot.city_name) && !numberOrNull(snapshot.city_id)),
    needs_district_lookup: Boolean(safeText(snapshot.district_name) && !numberOrNull(snapshot.district_id)),
    reply_text: replyText,
  },
}];

const base = $('Code Merge AddOrder Draft').first().json;
const row = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const numberOrNull = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};
const nhanhAccessToken = safeText(row.nhanh_access_token);
const nhanhAppId = numberOrNull(row.app_id);
const nhanhBusinessId = numberOrNull(row.business_id);
const canUseNhanh = Boolean(nhanhAccessToken && nhanhAppId && nhanhBusinessId);
let replyText = safeText(base.reply_text);

if (!replyText && !canUseNhanh && (base.needs_product_lookup || base.needs_city_lookup || base.needs_district_lookup || base.addorder_action === 'confirm')) {
  replyText = 'Thiếu cấu hình Nhanh.';
}

return [{
  json: {
    ...base,
    nhanh_access_token: nhanhAccessToken,
    nhanh_app_id: nhanhAppId,
    nhanh_business_id: nhanhBusinessId,
    nhanh_product_list_url: canUseNhanh ? ('https://pos.open.nhanh.vn/v3.0/product/list?appId=' + nhanhAppId + '&businessId=' + nhanhBusinessId) : '',
    nhanh_location_url: canUseNhanh ? ('https://pos.open.nhanh.vn/v3.0/shipping/location?appId=' + nhanhAppId + '&businessId=' + nhanhBusinessId) : '',
    nhanh_order_add_url: canUseNhanh ? ('https://pos.open.nhanh.vn/v3.0/order/add?appId=' + nhanhAppId + '&businessId=' + nhanhBusinessId) : '',
    product_lookup_body: canUseNhanh && base.needs_product_lookup && !replyText ? {
      filters: { name: base.product_query },
      paginator: { size: 5, sort: { id: 'desc' } },
    } : null,
    city_lookup_body: canUseNhanh && base.needs_city_lookup && !replyText ? {
      filters: { locationVersion: 'v1', type: 'CITY' },
    } : null,
    district_lookup_body: canUseNhanh && base.needs_district_lookup && !replyText && base.city_id ? {
      filters: { locationVersion: 'v1', type: 'DISTRICT', parentId: base.city_id },
    } : null,
    reply_text: replyText,
  },
}];

const base = $('If Needs Product Lookup').first().json;
const payload = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const numberOrNull = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

let replyText = safeText(base.reply_text);
const root = payload?.data ?? payload ?? {};
const rawItems = Array.isArray(root?.data) ? root.data : Array.isArray(root?.products) ? root.products : [];
const query = normalizeText(base.product_query);
const items = rawItems.map((item) => {
  const name = safeText(item.name);
  const code = safeText(item.code);
  const barcode = safeText(item.barcode);
  const price = numberOrNull(item?.prices?.retail ?? item?.prices?.price ?? item.price);
  const score = (() => {
    const normalizedName = normalizeText(name);
    const normalizedCode = normalizeText(code);
    const normalizedBarcode = normalizeText(barcode);
    if (query && (normalizedCode === query || normalizedBarcode === query)) return 100;
    if (query && normalizedName === query) return 98;
    if (query && normalizedName.includes(query) && normalizedCode.includes(query)) return 92;
    if (query && (normalizedName.includes(query) || normalizedCode.includes(query))) return 88;
    if (query && query.includes(normalizedCode) && normalizedCode) return 86;
    return 0;
  })();
  return {
    id: numberOrNull(item.id),
    code,
    name,
    price,
    score,
  };
}).filter((item) => item.id).sort((a, b) => (b.score - a.score) || a.name.localeCompare(b.name, 'vi'));

let chosen = null;
if (items.length === 1) {
  chosen = items[0];
} else if (items.length > 1 && items[0].score >= 98 && items[0].score > items[1].score) {
  chosen = items[0];
} else if (items.length > 1 && items[0].score >= 92 && items[1].score <= 80) {
  chosen = items[0];
}

if (!replyText) {
  if (payload.error || (typeof payload.code !== 'undefined' && Number(payload.code) !== 1 && !items.length)) {
    replyText = safeText(payload.message || payload.error || 'Không tìm được sản phẩm trên Nhanh.');
  } else if (!items.length) {
    replyText = 'Không tìm thấy sản phẩm khớp với "' + base.product_query + '".';
  } else if (!chosen) {
    const lines = ['Sản phẩm chưa rõ:'];
    for (const item of items.slice(0, 5)) {
      lines.push([item.code, item.name].filter(Boolean).join(' | '));
    }
    replyText = lines.join('\n');
  }
}

return [{
  json: {
    ...base,
    product_search_result: items,
    product_id: chosen?.id ?? base.product_id ?? null,
    product_code: chosen?.code ?? base.product_code ?? '',
    product_name: chosen?.name ?? base.product_name ?? '',
    unit_price: chosen?.price ?? base.unit_price ?? null,
    needs_product_lookup: false,
    reply_text: replyText,
  },
}];

const base = $('If Needs City Lookup').first().json;
const payload = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const aliasMap = {
  hcm: 'ho chi minh',
  tphcm: 'ho chi minh',
  'tp hcm': 'ho chi minh',
  'tp ho chi minh': 'ho chi minh',
  hn: 'ha noi',
  'tp ha noi': 'ha noi',
  dn: 'da nang',
  'tp da nang': 'da nang',
};
const canonical = (value) => aliasMap[normalizeText(value)] || normalizeText(value).replace(/^tp\s+/, '').replace(/^tinh\s+/, '');
const items = Array.isArray(payload?.data) ? payload.data : Array.isArray(payload?.result?.data) ? payload.result.data : [];
const query = canonical(base.city_name);
const mapped = items.map((item) => ({
  id: Number(item.id || 0) || null,
  name: safeText(item.name),
  otherName: safeText(item.otherName),
  score: (() => {
    const name = canonical(item.name);
    const other = canonical(item.otherName);
    if (name === query || other === query) return 100;
    if (name.includes(query) || query.includes(name) || other.includes(query)) return 90;
    return 0;
  })(),
})).filter((item) => item.id).sort((a, b) => (b.score - a.score) || a.name.localeCompare(b.name, 'vi'));
let chosen = null;
if (mapped.length === 1) chosen = mapped[0];
else if (mapped.length > 1 && mapped[0].score >= 100 && mapped[0].score > mapped[1].score) chosen = mapped[0];
else if (mapped.length > 1 && mapped[0].score >= 90 && mapped[1].score < 90) chosen = mapped[0];
let replyText = safeText(base.reply_text);
if (!replyText) {
  if (payload.error || (typeof payload.code !== 'undefined' && Number(payload.code) !== 1 && !mapped.length)) {
    replyText = safeText(payload.message || payload.error || 'Không tra được tỉnh/thành trên Nhanh.');
  } else if (!mapped.length) {
    replyText = 'Không tìm thấy tỉnh/thành khớp với "' + base.city_name + '".';
  } else if (!chosen) {
    replyText = 'Tỉnh/thành chưa rõ: ' + mapped.slice(0, 5).map((item) => item.name).join(', ');
  }
}
return [{
  json: {
    ...base,
    city_id: chosen?.id ?? base.city_id ?? null,
    city_name: chosen?.name ?? base.city_name ?? '',
    needs_city_lookup: false,
    location_search_result: {
      ...(base.location_search_result || {}),
      city_candidates: mapped,
    },
    reply_text: replyText,
  },
}];

const base = $('If Needs District Lookup').first().json;
const payload = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .replace(/^(quan|q|huyen|h)\s+/, '');
const items = Array.isArray(payload?.data) ? payload.data : Array.isArray(payload?.result?.data) ? payload.result.data : [];
const query = normalizeText(base.district_name);
const mapped = items.map((item) => ({
  id: Number(item.id || 0) || null,
  name: safeText(item.name),
  otherName: safeText(item.otherName),
  score: (() => {
    const name = normalizeText(item.name);
    const other = normalizeText(item.otherName);
    if (name === query || other === query) return 100;
    if (name.includes(query) || query.includes(name) || other.includes(query)) return 90;
    return 0;
  })(),
})).filter((item) => item.id).sort((a, b) => (b.score - a.score) || a.name.localeCompare(b.name, 'vi'));
let chosen = null;
if (mapped.length === 1) chosen = mapped[0];
else if (mapped.length > 1 && mapped[0].score >= 100 && mapped[0].score > mapped[1].score) chosen = mapped[0];
else if (mapped.length > 1 && mapped[0].score >= 90 && mapped[1].score < 90) chosen = mapped[0];
let replyText = safeText(base.reply_text);
if (!replyText) {
  if (payload.error || (typeof payload.code !== 'undefined' && Number(payload.code) !== 1 && !mapped.length)) {
    replyText = safeText(payload.message || payload.error || 'Không tra được quận/huyện trên Nhanh.');
  } else if (!mapped.length) {
    replyText = 'Không tìm thấy quận/huyện khớp với "' + base.district_name + '".';
  } else if (!chosen) {
    replyText = 'Quận/huyện chưa rõ: ' + mapped.slice(0, 5).map((item) => item.name).join(', ');
  }
}
return [{
  json: {
    ...base,
    district_id: chosen?.id ?? base.district_id ?? null,
    district_name: chosen?.name ?? base.district_name ?? '',
    needs_district_lookup: false,
    location_search_result: {
      ...(base.location_search_result || {}),
      district_candidates: mapped,
    },
    reply_text: replyText,
  },
}];

const row = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const digitsOnly = (value) => String(value || '').replace(/[^\d]/g, '');
const numberOrNull = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};
const formatMoney = (value) => {
  const parsed = numberOrNull(value);
  if (parsed === null) return '';
  return Math.round(parsed).toLocaleString('vi-VN') + 'đ';
};
const buildSummary = (title, snapshot, missing = [], ready = false) => {
  const lines = [title];
  if (snapshot.customer_name || snapshot.phone) {
    lines.push('Khách: ' + [snapshot.customer_name, snapshot.phone].filter(Boolean).join(' | '));
  }
  if (snapshot.product_name || snapshot.product_query) {
    const productTitle = snapshot.product_name || snapshot.product_query;
    lines.push('Sản phẩm: ' + productTitle + ' x' + snapshot.quantity);
  }
  const addressParts = [snapshot.address, snapshot.district_name, snapshot.city_name].filter(Boolean);
  if (addressParts.length) lines.push('Địa chỉ: ' + addressParts.join(', '));
  if (numberOrNull(snapshot.unit_price) !== null) lines.push('Giá: ' + formatMoney(snapshot.unit_price));
  if (safeText(snapshot.note)) lines.push('Ghi chú: ' + snapshot.note);
  if (missing.length) lines.push('Thiếu: ' + missing.join(', ') + '.');
  if (ready) lines.push('Dùng /addorder confirm t-' + row.ticket_id + ' để chốt.');
  return lines.join('\n');
};

const snapshot = {
  customer_name: safeText(row.customer_name),
  phone: digitsOnly(row.phone),
  address: safeText(row.address),
  city_name: safeText(row.city_name),
  city_id: numberOrNull(row.city_id),
  district_name: safeText(row.district_name),
  district_id: numberOrNull(row.district_id),
  ward_name: safeText(row.ward_name),
  ward_id: numberOrNull(row.ward_id),
  location_version: safeText(row.location_version) || 'v1',
  product_query: safeText(row.product_query),
  product_id: numberOrNull(row.product_id),
  product_code: safeText(row.product_code),
  product_name: safeText(row.product_name),
  unit_price: numberOrNull(row.unit_price),
  quantity: Math.max(1, Math.round(numberOrNull(row.quantity) || 1)),
  note: safeText(row.note),
  customer_ship_fee: numberOrNull(row.customer_ship_fee),
  deposit_amount: numberOrNull(row.deposit_amount),
  transfer_amount: numberOrNull(row.transfer_amount),
};

let replyText = safeText(row.reply_text);
let orderDraftStatus = safeText(row.order_draft_status);
let auditActionType = 'order_draft_upserted';
let canSubmitOrder = false;
const missing = [];
if (!snapshot.customer_name) missing.push('tên khách');
if (!snapshot.phone) missing.push('SĐT');
if (!snapshot.address) missing.push('địa chỉ');
if (!snapshot.city_id) missing.push('tỉnh/thành');
if (!snapshot.district_id) missing.push('quận/huyện');
if (!snapshot.product_id) missing.push('sản phẩm');
if (numberOrNull(snapshot.unit_price) === null) missing.push('giá bán');
if (!snapshot.quantity) missing.push('số lượng');

if (row.addorder_action === 'cancel') {
  orderDraftStatus = 'cancelled';
  auditActionType = 'order_draft_cancelled';
  replyText = replyText || ('Đã hủy draft đơn T-' + row.ticket_id + '.');
} else if (replyText) {
  orderDraftStatus = 'needs_clarification';
  auditActionType = row.addorder_action === 'confirm' ? 'order_draft_confirm_blocked' : 'order_draft_upserted';
} else if (row.addorder_action === 'show') {
  if (safeText(row.draft_row?.status) === 'created' || safeText(row.order_draft_status) === 'created') {
    orderDraftStatus = 'created';
    replyText = buildSummary('Đơn đã tạo cho T-' + row.ticket_id + '.', snapshot, [], false);
    if (row.nhanh_order_id) replyText += '\nMã Nhanh: ' + row.nhanh_order_id;
    if (safeText(row.created_order_tracking_url)) replyText += '\nTracking: ' + row.created_order_tracking_url;
    auditActionType = 'order_draft_viewed';
  } else {
    orderDraftStatus = missing.length ? 'needs_clarification' : 'ready_to_confirm';
    replyText = buildSummary('Draft đơn T-' + row.ticket_id + '.', snapshot, missing, orderDraftStatus === 'ready_to_confirm');
    auditActionType = 'order_draft_viewed';
  }
} else if (missing.length) {
  orderDraftStatus = 'needs_clarification';
  replyText = buildSummary(
    row.addorder_action === 'reset' ? ('Đã reset draft T-' + row.ticket_id + '.') : ('Đã cập nhật draft T-' + row.ticket_id + '.'),
    snapshot,
    missing,
    false,
  );
  auditActionType = row.addorder_action === 'confirm' ? 'order_draft_confirm_blocked' : 'order_draft_upserted';
} else {
  orderDraftStatus = 'ready_to_confirm';
  auditActionType = row.addorder_action === 'confirm' ? 'order_draft_confirm_requested' : 'order_draft_upserted';
  if (row.addorder_action === 'confirm') {
    canSubmitOrder = true;
    replyText = 'Đang tạo đơn trên Nhanh...';
  } else if (row.addorder_action === 'reset') {
    replyText = buildSummary('Đã reset draft T-' + row.ticket_id + '.', snapshot, [], true);
  } else {
    replyText = buildSummary('Đã cập nhật draft T-' + row.ticket_id + '.', snapshot, [], true);
  }
}

if ((snapshot.deposit_amount || snapshot.transfer_amount) && row.addorder_action !== 'cancel') {
  replyText += '\nLưu ý: cọc/chuyển khoản mới chỉ lưu draft, chưa đẩy sang Nhanh.';
}

const appOrderId = safeText(row.app_order_id) || ('zalo-t' + row.ticket_id + '-' + Date.now());
const orderAddPayload = canSubmitOrder ? {
  info: {
    type: 1,
    description: snapshot.note || ('Tạo từ ticket T-' + row.ticket_id),
  },
  channel: {
    appOrderId,
    sourceName: 'Zalo /addorder',
  },
  shippingAddress: {
    name: snapshot.customer_name,
    mobile: snapshot.phone,
    address: snapshot.address,
    cityId: snapshot.city_id,
    districtId: snapshot.district_id,
    locationVersion: snapshot.location_version,
    ...(snapshot.ward_id ? { wardId: snapshot.ward_id } : {}),
  },
  products: [
    {
      id: snapshot.product_id,
      price: snapshot.unit_price,
      quantity: snapshot.quantity,
      ...(snapshot.product_name ? { description: snapshot.product_name } : {}),
    },
  ],
} : {};

return [{
  json: {
    ...row,
    draft_snapshot: snapshot,
    app_order_id: appOrderId,
    order_add_request_body: orderAddPayload,
    can_submit_order: canSubmitOrder,
    should_save_draft: row.addorder_action !== 'show',
    order_draft_status: orderDraftStatus,
    audit_action_type: auditActionType,
    reply_text: replyText.trim(),
    handoff_queue_id: row.ticket_id || null,
  },
}];

const base = $('Code Finalize AddOrder Draft').first().json;
const payload = $input.first()?.json || {};
const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const data = payload?.data ?? payload?.result?.data ?? payload?.result ?? {};
let replyText = '';
let orderDraftStatus = 'failed';
let auditActionType = 'order_created_failed';
let nhanhOrderId = data?.id ?? null;
let trackingUrl = safeText(data?.trackingUrl);
let lastErrorCode = '';
let lastError = '';

if (payload.error || (typeof payload.code !== 'undefined' && Number(payload.code) !== 1)) {
  lastErrorCode = String(payload.code ?? payload.error_code ?? 'NHANH_API_ERROR');
  lastError = safeText(payload.message || payload.error || 'Tạo đơn trên Nhanh thất bại.');
  replyText = lastError;
} else {
  orderDraftStatus = 'created';
  auditActionType = 'order_created';
  replyText = 'Đã tạo đơn Nhanh ' + nhanhOrderId + '.';
  if (trackingUrl) replyText += '\nTracking: ' + trackingUrl;
}

return [{
  json: {
    ...base,
    nhanh_order_id: nhanhOrderId,
    created_order_tracking_url: trackingUrl,
    order_draft_status: orderDraftStatus,
    audit_action_type: auditActionType,
    reply_text: replyText,
    last_error_code: lastErrorCode,
    last_error: lastError,
    nhanh_response: payload,
    confirmed_at: orderDraftStatus === 'created' ? new Date().toISOString() : '',
    confirmed_by_user_id: orderDraftStatus === 'created' ? (base.sender_id || '') : '',
    confirmed_by_display_name: orderDraftStatus === 'created' ? (base.actor_display_name || base.sender_display_name || '') : '',
    handoff_queue_id: base.ticket_id || null,
  },
}];

const pick = (name) => {
  try {
    return $(name).first().json || {};
  } catch {
    return {};
  }
};

const finalBase = pick('Code Finalize AddOrder Draft');
const submitBase = pick('Code Normalize AddOrder Submit');
const row = $input.first()?.json || {};
const replyText = String(submitBase.reply_text || finalBase.reply_text || row.reply_text || 'Không xử lý được /addorder.').trim();
const auditActionType = String(submitBase.audit_action_type || finalBase.audit_action_type || 'order_draft_replied').trim() || 'order_draft_replied';

return [{
  json: {
    ...finalBase,
    ...submitBase,
    ...row,
    reply_text: replyText,
    audit_action_type: auditActionType,
    handoff_queue_id: finalBase.ticket_id || row.handoff_queue_id || null,
    order_draft_id: row.id || finalBase.order_draft_id || null,
    order_draft_status: submitBase.order_draft_status || finalBase.order_draft_status || row.status || '',
  },
}];
